# Testing len() with various object types
test_cases = {
    "String": "Hello World",
    "List": [1, 2, 3, 4],
    "Tuple": (1, 2, 3),
    "Dictionary": {"a": 1, "b": 2},
    "Set": {1, 2, 3, 3},
    "Range": range(0, 10)
}

results = {}
for name, obj in test_cases.items():
    results[name] = len(obj)

print(results)

# Testing an object that should fail (Integer)
try:
    len(123)
except TypeError as e:
    print(f"Integer error: {e}")
